import React, { useState, useEffect } from 'react';
import API from '../api';
import GameList from '../components/GameList';
import GameForm from '../components/GameForm';
import { useNavigate } from 'react-router-dom';

function Dashboard() {
  const [games, setGames] = useState([]);
  const navigate = useNavigate();

  useEffect(() => {
    const token = localStorage.getItem('token');
    if (!token) {
      navigate('/login');
      return;
    }

    fetchGames();
  }, []);

  const fetchGames = async () => {
    try {
      const res = await API.get('/games');
      setGames(res.data);
    } catch (err) {
      alert('Не удалось загрузить игры');
    }
  };

  // обработчики, передаваемые дочерним компонентам
  const handleAdd = async (game) => {
    try {
      await API.post('/games', game);
      fetchGames();
    } catch (err) {
      alert('Не удалось добавить игру');
    }
  };

  const handleDelete = async (id) => {
    try {
      await API.delete(`/games/${id}`);
      setGames(games.filter((g) => g._id !== id));
    } catch (err) {
      alert('Не удалось удалить');
    }
  };

  const handleEdit = async (id, updates) => {
    try {
      await API.put(`/games/${id}`, updates);
      fetchGames();
    } catch (err) {
      alert('Не удалось обновить');
    }
  };

  return (
    <div>
      <h2>Ваша библиотека игр</h2>
      <GameForm onAdd={handleAdd} />
      <GameList games={games} onDelete={handleDelete} onEdit={handleEdit} />
    </div>
  );
}

export default Dashboard;
